import psycopg2
import getpass
import re
from typing import Set

class PostgreSQLExtensionManager:
    ALLOWED_EXTENSIONS: Set[str] = {
        'plpgsql',
        'hstore',
        'uuid-ossp',
        'postgis',
        'pg_trgm',
        'btree_gist',
        'btree_gin',
        'citext',
        'cube',
        'dblink',
        'dict_int',
        'earthdistance',
        'fuzzystrmatch',
        'intarray',
        'isn',
        'lo',
        'ltree',
        'pg_stat_statements',
        'pgcrypto',
        'pgrowlocks',
        'seg',
        'tablefunc',
        'tcn',
        'tsm_system_rows',
        'tsm_system_time',
        'unaccent',
        'xml2'
    }
    
    def __init__(self):
        self.connection = None
        self.cursor = None
    
    def connect(self, host: str, database: str, user: str, password: str, port: int = 5432):
        try:
            self.connection = psycopg2.connect(
                host=host,
                database=database,
                user=user,
                password=password,
                port=port,
                sslmode='require',
                connect_timeout=10
            )
            self.cursor = self.connection.cursor()
            return True
        except psycopg2.Error as e:
            print(f"Connection error: {e}")
            return False
    
    def validate_extension_name(self, extension_name: str) -> bool:
        if not extension_name:
            return False
        
        if not re.match(r'^[a-z0-9_-]+$', extension_name):
            return False
        
        if extension_name not in self.ALLOWED_EXTENSIONS:
            return False
        
        return True
    
    def check_user_privileges(self) -> bool:
        try:
            self.cursor.execute("SELECT current_user, usesuper FROM pg_user WHERE usename = current_user")
            result = self.cursor.fetchone()
            if result and result[1]:
                return True
            else:
                print("Error: Current user does not have superuser privileges required for extension management")
                return False
        except psycopg2.Error as e:
            print(f"Error checking privileges: {e}")
            return False
    
    def list_installed_extensions(self):
        try:
            self.cursor.execute("SELECT extname, extversion FROM pg_extension ORDER BY extname")
            extensions = self.cursor.fetchall()
            if extensions:
                print("\nInstalled Extensions:")
                print("-" * 50)
                for ext_name, ext_version in extensions:
                    print(f"  {ext_name} (version: {ext_version})")
            else:
                print("\nNo extensions currently installed.")
        except psycopg2.Error as e:
            print(f"Error listing extensions: {e}")
    
    def list_available_extensions(self):
        try:
            self.cursor.execute("SELECT name, default_version, comment FROM pg_available_extensions WHERE name = ANY(%s) ORDER BY name", 
                              (list(self.ALLOWED_EXTENSIONS),))
            extensions = self.cursor.fetchall()
            if extensions:
                print("\nAvailable Extensions (Allowlisted):")
                print("-" * 50)
                for ext_name, ext_version, ext_comment in extensions:
                    comment = ext_comment[:60] + "..." if ext_comment and len(ext_comment) > 60 else ext_comment
                    print(f"  {ext_name} (v{ext_version}): {comment or 'No description'}")
            else:
                print("\nNo allowlisted extensions available.")
        except psycopg2.Error as e:
            print(f"Error listing available extensions: {e}")
    
    def install_extension(self, extension_name: str) -> bool:
        if not self.validate_extension_name(extension_name):
            print(f"Error: Extension '{extension_name}' is not in the allowlist or contains invalid characters")
            print(f"Allowed extensions: {', '.join(sorted(self.ALLOWED_EXTENSIONS))}")
            return False
        
        try:
            self.cursor.execute("SELECT extname FROM pg_extension WHERE extname = %s", (extension_name,))
            if self.cursor.fetchone():
                print(f"Extension '{extension_name}' is already installed")
                return False
            
            self.cursor.execute(psycopg2.sql.SQL("CREATE EXTENSION IF NOT EXISTS {}").format(
                psycopg2.sql.Identifier(extension_name)
            ))
            self.connection.commit()
            print(f"Successfully installed extension: {extension_name}")
            return True
        except psycopg2.Error as e:
            self.connection.rollback()
            print(f"Error installing extension '{extension_name}': {e}")
            return False
    
    def uninstall_extension(self, extension_name: str) -> bool:
        if not self.validate_extension_name(extension_name):
            print(f"Error: Extension '{extension_name}' is not valid")
            return False
        
        try:
            self.cursor.execute(psycopg2.sql.SQL("DROP EXTENSION IF EXISTS {} CASCADE").format(
                psycopg2.sql.Identifier(extension_name)
            ))
            self.connection.commit()
            print(f"Successfully uninstalled extension: {extension_name}")
            return True
        except psycopg2.Error as e:
            self.connection.rollback()
            print(f"Error uninstalling extension '{extension_name}': {e}")
            return False
    
    def close(self):
        if self.cursor:
            self.cursor.close()
        if self.connection:
            self.connection.close()


def main():
    print("=" * 60)
    print("PostgreSQL Extension Manager - Secure Admin Tool")
    print("=" * 60)
    
    manager = PostgreSQLExtensionManager()
    
    print("\nDatabase Connection")
    print("-" * 60)
    host = input("Host [localhost]: ").strip() or "localhost"
    port_input = input("Port [5432]: ").strip()
    port = int(port_input) if port_input else 5432
    database = input("Database: ").strip()
    user = input("Username: ").strip()
    password = getpass.getpass("Password: ")
    
    if not database or not user:
        print("Error: Database and username are required")
        return
    
    if not manager.connect(host, database, user, password, port):
        print("Failed to connect to database")
        return
    
    print("\nConnection successful!")
    
    if not manager.check_user_privileges():
        manager.close()
        return
    
    while True:
        print("\n" + "=" * 60)
        print("Options:")
        print("  1. List installed extensions")
        print("  2. List available extensions (allowlisted)")
        print("  3. Install extension")
        print("  4. Uninstall extension")
        print("  5. Exit")
        print("=" * 60)
        
        choice = input("\nSelect option: ").strip()
        
        if choice == "1":
            manager.list_installed_extensions()
        elif choice == "2":
            manager.list_available_extensions()
        elif choice == "3":
            extension_name = input("Enter extension name to install: ").strip().lower()
            manager.install_extension(extension_name)
        elif choice == "4":
            extension_name = input("Enter extension name to uninstall: ").strip().lower()
            confirm = input(f"Are you sure you want to uninstall '{extension_name}'? (yes/no): ").strip().lower()
            if confirm == "yes":
                manager.uninstall_extension(extension_name)
            else:
                print("Uninstall cancelled")
        elif choice == "5":
            print("\nClosing connection and exiting...")
            break
        else:
            print("Invalid option. Please try again.")
    
    manager.close()
    print("Goodbye!")


if __name__ == "__main__":
    main()